import axios from 'axios';

const backendURL = 'http://localhost:3000/api/qa';

// Get authorization header
const getAuthHeader = () => {
    const token = localStorage.getItem('token');
    return token ? { Authorization: token } : {};
};

// Get all QAs
export const getAllQAs = async () => {
    try {
        const response = await axios.get(backendURL);
        return response.data;
    } catch (error) {
        console.error('Get all QAs error:', error);
        throw error;
    }
};

// Create a new QA
export const createQA = async (qaData) => {
    try {
        const response = await axios.post(backendURL, qaData, {
            headers: getAuthHeader()
        });
        return response.data;
    } catch (error) {
        console.error('Create QA error:', error);
        throw error;
    }
};

// Get QA by ID
export const getQA = async (id) => {
    try {
        const response = await axios.get(`${backendURL}/${id}`);
        return response.data;
    } catch (error) {
        console.error('Get QA error:', error);
        throw error;
    }
};

// Update QA
export const updateQA = async (id, qaData) => {
    try {
        const response = await axios.put(`${backendURL}/${id}`, qaData, {
            headers: getAuthHeader()
        });
        return response.data;
    } catch (error) {
        console.error('Update QA error:', error);
        throw error;
    }
};

// Delete QA
export const deleteQA = async (id) => {
    try {
        const response = await axios.delete(`${backendURL}/${id}`, {
            headers: getAuthHeader()
        });
        return response.data;
    } catch (error) {
        console.error('Delete QA error:', error);
        throw error;
    }
};

// Get QAs by subject
export const getQAsBySubject = async (subjectId) => {
    try {
        const response = await axios.get(`${backendURL}/subject/${subjectId}`);
        return response.data;
    } catch (error) {
        console.error('Get QAs by subject error:', error);
        throw error;
    }
};

