        const response = await axios.get(`${backendURL}/level/${levelId}`);
        return response.data;
    } catch (error) {
        console.error('Get QAs by level error:', error);
        throw error;
    }
};

// Answer QA
export const answerQA = async (answerData) => {
    try {
        const response = await axios.post(`${backendURL}/answer`, answerData, {
            headers: getAuthHeader()
        });
        return response.data;
    } catch (error) {
        console.error('Answer QA error:', error);
        throw error;
    }
};

// Get recommended QAs
export const getRecommendedQAs = async (userId) => {
    try {
        const response = await axios.get(`${backendURL}/recommended/${userId}`, {
            headers: getAuthHeader()
        });
        return response.data;
    } catch (error) {
        console.error('Get recommended QAs error:', error);
        throw error;
    }
};
